const row = $input.first().json;
const listings = typeof row.listings === 'string' ? JSON.parse(row.listings) : (row.listings || []);
const anzahl = Number(row.anzahl) || 0;

if (!anzahl) {
  return [{ json: { anzahl: 0, ids: [], htmlBody: '', updateSql: '' } }];
}

const ids = listings.map(l => l.id);
const datum = new Date().toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit', year: 'numeric' });

const rows = listings.map(l => {
  const preis = l.preis
    ? (l.preis >= 10000 ? Math.round(l.preis / 1000) + 'k EUR' : Math.round(l.preis) + ' EUR')
    : (l.preis_pro_m2 ? Math.round(l.preis_pro_m2) + ' EUR/m\u00b2' : '\u2013');
  const ort = [l.plz, l.gemeinde_landkreis].filter(Boolean).join(' ') || '\u2013';
  const url = l.url_offiziell
    ? '<a href="' + l.url_offiziell + '" style="color:#2563eb;">Details</a>'
    : '\u2013';
  return '<tr style="border-bottom:1px solid #e5e7eb;">'
    + '<td style="padding:10px 12px;font-weight:600;color:#111827;">' + (l.titel || '\u2013') + '</td>'
    + '<td style="padding:10px 12px;color:#374151;">' + ort + '</td>'
    + '<td style="padding:10px 12px;color:#374151;">' + preis + '</td>'
    + '<td style="padding:10px 12px;color:#374151;">' + (l.quelle || '\u2013') + '</td>'
    + '<td style="padding:10px 12px;">' + url + '</td>'
    + '</tr>';
}).join('');

const htmlBody = '<!DOCTYPE html><html lang="de"><head><meta charset="UTF-8"></head>'
  + '<body style="margin:0;padding:0;background:#f9fafb;font-family:Arial,sans-serif;">'
  + '<table width="100%" cellpadding="0" cellspacing="0" style="background:#f9fafb;padding:32px 0;">'
  + '<tr><td align="center">'
  + '<table width="700" cellpadding="0" cellspacing="0" style="background:#fff;border-radius:8px;overflow:hidden;box-shadow:0 1px 3px rgba(0,0,0,.1);">'
  + '<tr style="background:#7c3aed;">'
  + '<td colspan="5" style="padding:24px 28px;">'
  + '<p style="margin:0;color:#ede9fe;font-size:13px;letter-spacing:.05em;">iKISS GEMEINDEN \u00b7 ' + datum + '</p>'
  + '<h1 style="margin:4px 0 0;color:#fff;font-size:22px;font-weight:700;">' + anzahl + ' neue Grundst\u00fcck' + (anzahl !== 1 ? 'e' : '') + '</h1>'
  + '<p style="margin:4px 0 0;color:#c4b5fd;font-size:14px;">Isen\u00bcttel \u00b7 Meinersen \u00b7 Wesendorf \u00b7 Lachendorf \u00b7 Lehre \u00b7 Papenteich</p>'
  + '</td></tr>'
  + '<tr><td colspan="5" style="padding:0;">'
  + '<table width="100%" cellpadding="0" cellspacing="0">'
  + '<thead><tr style="background:#f3f4f6;">'
  + '<th style="padding:10px 12px;text-align:left;font-size:12px;color:#6b7280;font-weight:600;text-transform:uppercase;">Titel</th>'
  + '<th style="padding:10px 12px;text-align:left;font-size:12px;color:#6b7280;font-weight:600;text-transform:uppercase;">Ort</th>'
  + '<th style="padding:10px 12px;text-align:left;font-size:12px;color:#6b7280;font-weight:600;text-transform:uppercase;">Preis</th>'
  + '<th style="padding:10px 12px;text-align:left;font-size:12px;color:#6b7280;font-weight:600;text-transform:uppercase;">Quelle</th>'
  + '<th style="padding:10px 12px;text-align:left;font-size:12px;color:#6b7280;font-weight:600;text-transform:uppercase;">Link</th>'
  + '</tr></thead><tbody>' + rows + '</tbody>'
  + '</table></td></tr>'
  + '<tr style="background:#f9fafb;"><td colspan="5" style="padding:16px 28px;border-top:1px solid #e5e7eb;">'
  + '<p style="margin:0;color:#9ca3af;font-size:12px;">Automatisch generiert \u00b7 iKISS Gemeinden Scraper \u00b7 Niedersachsen</p>'
  + '</td></tr></table></td></tr></table></body></html>';

const updateSql = 'UPDATE listings SET exported_at = NOW() WHERE id IN (' + ids.join(',') + ')';

return [{ json: { anzahl, ids, htmlBody, updateSql } }];

const row = $('Neue Listings abfragen').first().json;
const listings = typeof row.listings === 'string' ? JSON.parse(row.listings) : (row.listings || []);
const datum = new Date().toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit', year: 'numeric' });

return listings.map(l => ({
  json: {
    id:           l.id,
    datum:        datum,
    titel:        l.titel || '\u2013',
    plz:          l.plz || '',
    gemeinde:     l.gemeinde_landkreis || '',
    preis_eur:    l.preis ? Math.round(l.preis) : '',
    preis_pro_m2: l.preis_pro_m2 ? Math.round(l.preis_pro_m2) : '',
    quelle:       l.quelle || '',
    url:          l.url_offiziell || ''
  }
}));
